var e=JSON.parse(`[{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"여긴……?","JPN":"ここは……？","ENG":"Where am I...?","TWN":"這裡是……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"정신이 들어, 소령? 여긴 아이기스의 내부야.","JPN":"気が付いたか、少佐？　ここはアイギスの艦内だ。","ENG":"Are you awake, Major? You're in Aegis.","TWN":"你醒了，少校？這裡是埃癸斯的內艙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"안토노프 양이 우릴 구해줘서…… 지금 우리는 이면세계를 표류하고 있어.","JPN":"アントノフさんが僕たちを助けてくれて……今裏世界を漂流している。","ENG":"Antonov saved us... We're currently drifting in Counterside.","TWN":"安東諾夫救了我們……現在我們正在異界漂流。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이면세계?","JPN":"裏世界？","ENG":"Counterside?","TWN":"異界？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Kgh!","TWN":"咳呃！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아, 아직 움직이지 않는 게 좋아. 전신 타박상에, 피도 많이 흘렸으니까.","JPN":"あ、まだ動かない方がいいよ。全身に打撲傷があって、出血も酷かったから。","ENG":"Ah, you'd better not move. You're bruised all over and have lost a lot of blood.","TWN":"先不要亂動，你全身多處挫傷，還流了好多血。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그리고 저, 그 눈은…….","JPN":"それから、その目なんだけど……","ENG":"And, uh... your right eye...","TWN":"還有那個，你的眼睛……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"알고 있어요. 찔렸을 때부터, 직감했으니까.","JPN":"わかっています。刺された時点で直感しましたから。","ENG":"I know. I knew the moment it got stabbed.","TWN":"我知道，被擊中的時候，我就感覺到了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"더는 싸울 수 없겠죠. 주안을 잃어버린 저격수는.","JPN":"もう戦えないですよね。主眼を失った狙撃手は。","ENG":"There is no place on the battlefield for a sniper who has lost her dominant eye.","TWN":"一個失去主眼的狙擊手，我已經無法再戰鬥了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"괜찮아요, 박사님. 이제 전 싸울 생각 없으니까요.","JPN":"大丈夫です、博士。私はもう戦うつもりはありませんから。","ENG":"It's all right, Doctor. I have no intention of fighting anymore.","TWN":"沒關係，博士。我也不想繼續戰鬥了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우린 할 만큼 했어요.","JPN":"私たちは十分頑張りました。","ENG":"We did what we could.","TWN":"我們已經盡力了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까, 이젠 결과를 받아들여요.","JPN":"だから、もう結末を受け入れましょう。","ENG":"It's time... we accepted the outcome.","TWN":"所以，現在就接受結果吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"무슨 헛소리를 하는 거야! 결과를 받아들여? 무슨 결과!","JPN":"何を訳のわかんないこと言ってんだよ！　結末を受け入れるだ？　なんの結末だよ！","ENG":"What kind of nonsense is that? Accept the outcome? What outcome?!","TWN":"你在說什麼鬼話！接受結果？什麼結果！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"아직 아무것도 안 끝났어! 승부는 9회말 2아웃까지 모르는 거라고!","JPN":"まだ何も終わっちゃいない！　勝負は9回裏2アウトまでわからないもんだろ！","ENG":"Nothing's over yet! The real competition starts with 2 outs in the bottom of the 9th inning!","TWN":"一切都還沒結束呢！勝負是從九局下半二出局開始的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"현실세계에서 마스터는 지금 아포리아와 목숨을 걸고 싸우고 있어!","JPN":"マスターは今、現実世界でアポリアと命懸けで戦ってるんだ！","ENG":"Master is in Normalside fighting with Aporia right now!","TWN":"大姊還在現世中與阿波利亞殊死對決！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"이 배가 사라지지 않았다는 건, 아직 마스터가 살아있다는 증거야!","JPN":"この船が消えてないってことは、まだマスターが生きてるってことだ！","ENG":"Since this ship hasn't disappeared yet, it's proof that Master's still alive!","TWN":"這艘船還沒有消失，就代表大姊還活著！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇다는 말은 반대로 그자가 현실세계에서 죽어버리면, 이 세계에 갇혀 영영 나갈 수 없다는 말이겠군요.","JPN":"ということは、逆にあの者が現実世界で死んでしまったら、私たちはこの世界から永遠に出られないということですよね。","ENG":"In other words, if she dies in Normalside, we are trapped in Counterside forever.","TWN":"反過來說就是，如果她在現世中死去，我們就會永遠被困在這個世界裡無法出去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"참도 고맙네요. 애초에 우린 당신들에게 와달라고 부탁한 적도 없는데.","JPN":"有難迷惑です。そもそもあなたたちに来てほしいと頼んでもいないのに。","ENG":"How thoughtful of you all. We never even asked for you to come and help us in the first place.","TWN":"還真是謝謝你們，不過我從沒要你們幫忙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고!? 지금 해보자는 거야!?","JPN":"何だと！？　やろうってのか！？","ENG":"What did you just say?! You wanna piece of me, is that it?!","TWN":"你說什麼？！你要嚐嚐我的厲害嗎？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"머리가 아프네요. 다들 돌아가주세요.","JPN":"頭が痛いわ。皆さん出て行ってください。","ENG":"I have a headache. Please leave, everyone.","TWN":"我現在頭很痛，請大家先回去吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"혼자 있고 싶으니까.","JPN":"一人になりたいので。","ENG":"I want to be alone.","TWN":"我想一個人靜一靜。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"이거, 이거 실망이에요. 카린 양.","JPN":"これはこれは。がっかりです、カリンさん。","ENG":"My, I'm disappointed, Karin.","TWN":"真令人失望，卡琳。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영…… 씨.","JPN":"シノン……さん。","ENG":"Shiyoung...","TWN":"時雨……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이래봬도 저 카린 양을 꽤 좋아했다고요.","JPN":"これでも私、結構カリンさんのこと好きだったんですけどね。","ENG":"You know, I really liked you, Karin.","TWN":"我可是很喜歡那個卡琳的喔。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"머리는 좋은데, 그에 비해 융통성 없고 고집 센 것도…….","JPN":"頭は良いのに、融通が利かなくて、意地っ張りで……","ENG":"You're smart, but also stubborn like a mule, and strict...","TWN":"頭腦聰明，雖然有些不知變通和固執……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어딘가 어설퍼 보이면서도, 누가 뭐래도 끝까지 포기하지 않고 노력하는 점도…….","JPN":"どこか不器用で、でも何を言われても最後まで諦めずに努力し続けるところも……","ENG":"Clumsy at times, but you never give up no matter what anyone says...","TWN":"有時候很笨拙，但不管別人怎麼說，也絕不會放棄努力……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그리고 누구보다 걱정이 많고, 눈물이 많은 것도요.","JPN":"そして誰よりも心配性で、涙もろいところも。","ENG":"I also know that you worry more than anyone and that you're emotional.","TWN":"還有比任何人都愛操心，眼淚也很多。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭐, 잔소리가 조금 많지만, 그건 그만큼 다른 사람들을 신경 쓰고 있다는 뜻이니까요.","JPN":"まぁ、小言は多い方ですが、それはそれだけ周りを気にかけている証拠でもありますから。","ENG":"Well, you do nag a lot, but that just means that you care for others.","TWN":"呃，雖說有一些嘮叨，但那也是因為關心別人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하지만 지금의 카린 양은 실망이에요, 대실망!","JPN":"それなのに、今のカリンさんにはがっかりです、大失望です！","ENG":"But the Karin right now, I'm disappointed in her. Like, a lot!","TWN":"但是現在的卡琳，我對她真的非常、非常失望！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하고 싶은 말이 뭔가요?","JPN":"何が言いたいんですか？","ENG":"What is it that you wish to say?","TWN":"你想要說什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그야, 아포리아와의 싸움에서…… 카린 양, 죽으려고 했잖아요.","JPN":"ほら、アポリアとの戦いで……カリンさんが、死のうとしたじゃないですか。","ENG":"You know, during the fight with Aporia... you tried to die, Karin.","TWN":"你與阿波利亞作戰的時候……其實，是想要尋死吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"세계를 끝까지 지키겠다고 했으면서, 살 수 있는 한 최대한 살아보겠다고 했으면서.","JPN":"世界を守り抜くと言ったくせに、最後の最後まで生き抜くって言ったくせに。","ENG":"You promised to protect this world until the end and that you'd survive for as long as you could.","TWN":"明明說好了要至死守護這個世界，為此也要竭盡全力地活下去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"스스로를 희생해서 그렇게 저를 살리면, 제가 고맙다고 할 줄 알았어요?","JPN":"自分を犠牲にして私を助けたら、私が感謝すると思ったんですか？","ENG":"And you think that I'd be grateful if you saved my life by sacrificing yourself?","TWN":"你以為犧牲自己救我，我就會很感激你嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"왜 자꾸 죽은 사람과 자기를 비교하면서, 스스로를 막다른 길로 몰아세우는 건데요!","JPN":"もう死んだ人と自分を比べ続けて、自分を逃げ場のないところに追い込んでどうするんですか！","ENG":"Why do you always compare yourself to a dead person and corner yourself?!","TWN":"為什麼總是要拿自己與不在了的人比較，把自己逼上絕路！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네는 평생 자네가 존경하는 사람의 그림자를 쫓는 운명이니까 말이야.","JPN":"君は一生、憧れの存在の影を追いかける運命だからな。","ENG":"Because you are destined to spend your entire life chasing the shadow of the one you admire.","TWN":"因為你註定要一輩子追逐最尊敬之人的影子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐라고?","JPN":"何ですって？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 그저 존경만으로 그림자를 쫓는 건, 언젠가 벽에 부딪치고 말 거야.","JPN":"しかし憧れだけで影を追いかけるのでは、いずれ壁にぶち当たってしまう。","ENG":"But you're bound to hit a dead end by merely chasing after a shadow with respect.","TWN":"但光靠著滿腔敬意去追逐那道影子，總有一天是會碰壁的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그건 누구보다 내가 가장 잘 알고 있네.","JPN":"私が誰よりもそれを良く知っている。","ENG":"I know that better than anyone.","TWN":"這我比任何人都清楚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그럼, 제가 뭘…… 어떻게 더 해야 하는 건데요.","JPN":"じゃあ、私はいったい……これ以上何をどうすればいいんですか。","ENG":"Then what else... must I do?","TWN":"那，我……該怎麼做。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제와서 제가 대체 뭘 할 수 있다는 거죠……?","JPN":"これ以上私にいったい何ができるって言うんですか……？","ENG":"What's left for me to do now...?","TWN":"事到如今，我到底還能做些什麼呢……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그걸 제가 어떻게 알겠어요! 사람은 원래 번뇌 속에서 길을 헤매는 법인데!","JPN":"私だって知りませんよ！　人は煩悩の中で迷い悩むものでしょ！","ENG":"How should I know that?! People are meant to wander and get lost in Kleshas!","TWN":"我怎麼知道！人這種生物，本來就是會在煩惱中不斷地徘徊！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"번뇌?","JPN":"煩悩？","ENG":"Kleshas?","TWN":"煩惱？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우린 지금껏 한 번도 포기하지 않았어요. 그리고 그 결과, 이렇게 지금까지 살아남았죠.","JPN":"私たちはこれまで一度も諦めたことがありません。そしてその結果、今こうして生き残っています。","ENG":"We have never given up, not even once. And as a result, we survived.","TWN":"我們至今連一次也沒有放棄過，結果就這樣活到了今天。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양이 길잡이를 해주지 않았다면, 아무도 여기까지 올 수 없었을 거라고요.","JPN":"カリンさんが導いてくれなかったら、誰一人ここまでは来れなかった。","ENG":"If you weren't there to guide us, no one would be here right now.","TWN":"要不是卡琳的帶領，我們也沒法走那麼遠。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그러니까 좀 더 자기 자신을 자랑스럽게 생각해도 괜찮다구요.","JPN":"だから、もう少し自分を誇ってもいいんですよ。","ENG":"All I'm saying is that it's okay to be more proud of yourself.","TWN":"所以卡琳，你可以以你自己為傲。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨…… 저는…….","JPN":"シノンさん……私は……","ENG":"Shiyoung... I...","TWN":"時雨……我……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"이 소리는?","JPN":"今の音は？","ENG":"That sound...","TWN":"這個聲音？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"아무래도 불청객 신세인 우리를 혼내 주러 온 모양인데?","JPN":"どうやら招かれざる客のオレたちを叱りにきたみたいだぞ？","ENG":"They appear to be here to evict us.","TWN":"看來是把我們當成了不速之客？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"어때? 아무래도 지금은 힘을 합하는 게 좋겠지, 칼잡이?","JPN":"どうだ？　今は力を合わせた方がいいんじゃないか、ナイフ使い？","ENG":"What do you think? Wouldn't it be wise to join forces for now, swordie?","TWN":"怎麼樣？現在可是聯手的好時機，用刀的？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아, 친한 척하지 말아 주실래요, 애송이 씨? 우린 아직 어색한 사이라고요?","JPN":"はあ、馴れ馴れしくするのはやめていただけますか、半人前さん？　まだ気は許してませんよ？","ENG":"*Sigh* Will you stop trying to act like we're all buddy-buddy, kid? We're not that close.","TWN":"哈……少跟我裝熟，小鬼？我們還不熟呢？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 그런 걸 따지는 성격이었어?","JPN":"何だよ、そういうのを気にする性格だったのか？","ENG":"Whoa, I didn't take you to be picky like that.","TWN":"什麼嘛，你這麼小氣喔？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"내가 자랐던 뒷골목에서는 영원한 적도, 영원한 아군도 없다고.","JPN":"オレが育った裏路地には、永遠の敵も永遠の味方もいなかったぞ。","ENG":"In the back alley where I'm from, we don't have absolute enemies or friends.","TWN":"我是在街頭長大的，沒有永遠的敵人，也沒有永遠的友軍。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"중요한 건, 어찌됐든 하루하루를 살아남는 거니까 말이지.","JPN":"どうにかして毎日を生き延びることの方が大事だったからな。","ENG":"Surviving each day was the only thing that mattered.","TWN":"只要能活過每一天，其他的都不重要。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아, 불안하긴 하지만 오늘은 특별히 제 뒤를 맡겨드리죠.","JPN":"はぁ、心もとないですけど、今日は特別に後ろを頼みます。","ENG":"*Sigh* I'm a little anxious about this, but I'll let you have my back for today.","TWN":"哀，雖然有些不安，不過今天就把我的命交在你手裡吧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼, 카린 양. 조금 쉬고 계세요.","JPN":"では、カリンさん。しばらく休んでいてください。","ENG":"Then, Karin. Rest a little, okay?","TWN":"那你先好好休息吧，卡琳。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"박사님, 단 둘이 있다고 마음 약해진 카린 양한테 엉큼한 수작 부리면 안 돼요?","JPN":"博士、二人きりだからって気持ちが弱っているカリンさんに、変なことしちゃダメですからね？","ENG":"Hey Doc, don't you dare make a move on Karin just because she seems needy and you're alone with her, okay?","TWN":"博士，你們二個單獨相處的時候，可不能對心軟的卡琳動壞心眼喔？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"무, 무, 무슨 헛소리야! 이 변태 용병이!","JPN":"な、な、何の話だ！　この変態傭兵が！","ENG":"W-w-what the heck are you implying?! You perverted merc!","TWN":"胡，胡，胡說什麼呢！你這個變態傭兵！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네, 고마워요. 시영 씨.","JPN":"はい、ありがとうございます。シノンさん。","ENG":"I will. Thank you, Shiyoung.","TWN":"嗯，時雨，謝謝你。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};